-- ============================================================================
-- CALIFORNIA development_reports seed — REPRODUCIBLE pg_net REFRESH SCRIPT
-- (pattern: docs/michigan-development-reports-seed.sql; run in the Supabase SQL editor)
--
-- Prepared 2026-07-16 (during the Supabase outage; batch runs when the DB returns):
-- all 523 modeled CA ZIPs (San Diego/Orange/Santa Clara/Alameda/Contra Costa/Sonoma/Ventura/San Mateo/San Luis Obispo/Marin).
-- Centroids pinned to zipcodes PyPI v3.0.0 (offline USPS dataset); 0 quarantined;
-- all bbox-validated. First-party permit sources are wired in the CA wire pass
-- (docs/source-registry.md "CALIFORNIA WIRE PASS") before this batch fires — this header
-- is finalized with the wired-source list in the go-live PR.
-- INDEX POLICY: substance gate stamps indexable automatically; throttled sitemap
-- (250 newcomers/day) rolls new pages in — no manual flip.
-- ============================================================================
drop table if exists public._ca_zips;
create table public._ca_zips(zip text primary key, lat float8, lng float8);

-- FIRE in waves of ~90 (offset 0/90/180/…; wait ~2.5 min per wave) -------------------
select count(net.http_post(
  'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
  jsonb_build_object('zip', zip, 'lat', lat, 'lng', lng),
  '{}'::jsonb, '{"Content-Type":"application/json"}'::jsonb, 120000)) as fired
from (select * from public._ca_zips order by zip limit 90 offset 0) w;

-- COLLECT after each wave (transient-safe upsert) -----------------------------------
select (j->>'zip'), (j->'home'->>'lat')::float8, (j->'home'->>'lng')::float8, j->'counts', j->'sites',
       coalesce((j->>'paywall')::bool,false),
       'zipcodes PyPI v3.0.0 centroid; get-address-report ZIP mode; California batch 2026-07-16',
       now()
from (
  select distinct on ((content::jsonb->>'zip')) content::jsonb j
  from net._http_response resp
  where resp.status_code = 200 and left(ltrim(resp.content),1)='{'
    and (content::jsonb->>'zip') in (select zip from public._ca_zips)
    and resp.created > now() - interval '30 minutes'
  order by (content::jsonb->>'zip'), resp.created desc
) r
on conflict (zip) do update set home_lat=excluded.home_lat, home_lng=excluded.home_lng,
  counts=excluded.counts, sites=excluded.sites, paywall=excluded.paywall,
  source_vintage=excluded.source_vintage, refreshed_at=excluded.refreshed_at
where jsonb_array_length(excluded.sites) > 0 or jsonb_array_length(public.development_reports.sites) = 0;

-- RE-FIRE stragglers (180s timeout), then re-collect --------------------------------
select count(net.http_post(
  'https://qwnnmljucajnexpxdgxr.supabase.co/functions/v1/get-address-report',
  jsonb_build_object('zip', z.zip, 'lat', z.lat, 'lng', z.lng),
  '{}'::jsonb, '{"Content-Type":"application/json"}'::jsonb, 180000)) as refired
from public._ca_zips z
where not exists (select 1 from public.development_reports dr where dr.zip = z.zip);

-- MATERIALIZE + verify ---------------------------------------------------------------
select public.app_refresh_all();
select (select count(*) from public.development_reports dr join public._ca_zips z on z.zip=dr.zip) as ca_cached,
       (select count(*) from public.app_community_meta m join public._ca_zips z on z.zip=m.zip where m.indexable) as ca_indexable;
